class UndergroundSystem:

    def __init__(self):
        self.check_ins = {}  # id: (startStation, checkInTime)
        self.travel_data = {}  # (startStation, endStation): {'total_time': int, 'count': int}

    def checkIn(self, id: int, stationName: str, t: int) -> None:
        self.check_ins[id] = (stationName, t)

    def checkOut(self, id: int, stationName: str, t: int) -> None:
        start_station, check_in_time = self.check_ins.pop(id)
        end_station = stationName
        travel_time = t - check_in_time

        route = (start_station, end_station)

        if route not in self.travel_data:
            self.travel_data[route] = {'total_time': 0, 'count': 0}

        self.travel_data[route]['total_time'] += travel_time
        self.travel_data[route]['count'] += 1

    def getAverageTime(self, startStation: str, endStation: str) -> float:
        route = (startStation, endStation)
        data = self.travel_data[route]
        return data['total_time'] / data['count']
